import { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Plus, Search, Edit2, Trash2, Calendar, Clock, User, Phone, 
  FileText, CheckCircle, AlertCircle, Timer, Filter, X, Bell, AlertTriangle, Cake
} from 'lucide-react'
import { customersAPI } from '../services/api'
import { servicesAPI } from '../services/api'
import { subServicesAPI } from '../services/api'

const Reminder = () => {
  const [reminders, setReminders] = useState([])
  const [customers, setCustomers] = useState([])
  const [services, setServices] = useState([])
  const [subServices, setSubServices] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [showForm, setShowForm] = useState(false)
  const [editingReminder, setEditingReminder] = useState(null)
  const [customerSearch, setCustomerSearch] = useState('')
  const [showCustomerList, setShowCustomerList] = useState(false)
  const [alertFilter, setAlertFilter] = useState('all') // 'all', 'today', 'birthday'
  
  const [formData, setFormData] = useState({
    customerId: '',
    customerName: '',
    cellNo: '',
    customerBirthday: '',
    registerDate: new Date().toISOString().split('T')[0],
    services: [],
    subServices: [],
    applicationNo: '',
    serviceStatus: 'applied',
    durationValue: '',
    durationType: 'days',
    reminderDate: '',
    notes: ''
  })

  // Service status options
  const serviceStatusOptions = [
    { value: 'applied', label: 'Applied', color: 'blue' },
    { value: 'pending', label: 'Pending', color: 'yellow' },
    { value: 'completed', label: 'Completed', color: 'green' }
  ]

  // Duration type options
  const durationTypes = [
    { value: 'days', label: 'Days' },
    { value: 'months', label: 'Months' },
    { value: 'years', label: 'Years' }
  ]

  useEffect(() => {
    fetchData()
  }, [])

  useEffect(() => {
    // Auto-calculate reminder date when duration changes
    if (formData.registerDate && formData.durationValue) {
      calculateReminderDate()
    }
  }, [formData.registerDate, formData.durationValue, formData.durationType])

  const fetchData = async () => {
    try {
      setLoading(true)
      
      // Fetch customers from API
      try {
        const customersResponse = await customersAPI.getAll()
        setCustomers(customersResponse.data)
      } catch (apiError) {
        // Fallback to localStorage if API fails
        console.log('API failed, using localStorage for customers')
        const storedCustomers = localStorage.getItem('customers')
        if (storedCustomers) {
          setCustomers(JSON.parse(storedCustomers))
        }
      }

      // Fetch services from API
      try {
        const servicesResponse = await servicesAPI.getAll()
        setServices(servicesResponse.data)
      } catch (apiError) {
        // Fallback to localStorage if API fails
        console.log('API failed, using localStorage for services')
        const storedServices = localStorage.getItem('services')
        if (storedServices) {
          setServices(JSON.parse(storedServices))
        } else {
          // Default services for testing
          const defaultServices = [
            { _id: '1', serviceName: 'Aadhaar Services' },
            { _id: '2', serviceName: 'PAN Card' },
            { _id: '3', serviceName: 'Passport' },
            { _id: '4', serviceName: 'IT Returns' },
            { _id: '5', serviceName: 'Insurance' },
            { _id: '6', serviceName: 'Printing' },
            { _id: '7', serviceName: 'Scanning' },
            { _id: '8', serviceName: 'Lamination' },
            { _id: '9', serviceName: 'Binding' },
            { _id: '10', serviceName: 'Photocopy' }
          ]
          setServices(defaultServices)
          localStorage.setItem('services', JSON.stringify(defaultServices))
        }
      }

      // Fetch sub-services
      try {
        const subServicesResponse = await subServicesAPI.getAll()
        setSubServices(subServicesResponse.data || [])
        console.log('Sub-services loaded:', subServicesResponse.data)
      } catch (apiError) {
        // Fallback to localStorage if API fails
        console.log('API failed, using localStorage for sub-services')
        const storedSubServices = localStorage.getItem('subServices')
        if (storedSubServices) {
          setSubServices(JSON.parse(storedSubServices))
        } else {
          // Default sub-services for testing - include Aadhaar Services
          const defaultSubServices = [
            // Aadhaar Services
            { _id: '1', serviceName: 'Aadhaar Services', subServiceName: 'Aadhaar Enrollment' },
            { _id: '2', serviceName: 'Aadhaar Services', subServiceName: 'Aadhaar Update' },
            { _id: '3', serviceName: 'Aadhaar Services', subServiceName: 'Aadhaar Correction' },
            { _id: '4', serviceName: 'Aadhaar Services', subServiceName: 'Aadhaar Print' },
            
            // Printing Services
            { _id: '5', serviceName: 'Printing', subServiceName: 'Document Printing' },
            { _id: '6', serviceName: 'Printing', subServiceName: 'Photo Printing' },
            { _id: '7', serviceName: 'Printing', subServiceName: 'Banner Printing' },
            
            // Scanning Services
            { _id: '8', serviceName: 'Scanning', subServiceName: 'Document Scanning' },
            { _id: '9', serviceName: 'Scanning', subServiceName: 'Photo Scanning' },
            
            // Lamination Services
            { _id: '10', serviceName: 'Lamination', subServiceName: 'Paper Lamination' },
            { _id: '11', serviceName: 'Lamination', subServiceName: 'Card Lamination' },
            
            // Binding Services
            { _id: '12', serviceName: 'Binding', subServiceName: 'Book Binding' },
            { _id: '13', serviceName: 'Binding', subServiceName: 'Spiral Binding' },
            
            // Photocopy Services
            { _id: '14', serviceName: 'Photocopy', subServiceName: 'Black & White Copy' },
            { _id: '15', serviceName: 'Photocopy', subServiceName: 'Color Copy' },
            
            // PAN Card Services
            { _id: '16', serviceName: 'PAN Card', subServiceName: 'PAN Card Application' },
            { _id: '17', serviceName: 'PAN Card', subServiceName: 'PAN Card Correction' },
            { _id: '18', serviceName: 'PAN Card', subServiceName: 'PAN Card Reprint' },
            
            // Passport Services
            { _id: '19', serviceName: 'Passport', subServiceName: 'Passport Application' },
            { _id: '20', serviceName: 'Passport', subServiceName: 'Passport Renewal' },
            { _id: '21', serviceName: 'Passport', subServiceName: 'Passport Photo' },
            
            // IT Returns
            { _id: '22', serviceName: 'IT Returns', subServiceName: 'ITR Filing' },
            { _id: '23', serviceName: 'IT Returns', subServiceName: 'Tax Planning' },
            { _id: '24', serviceName: 'IT Returns', subServiceName: 'Tax Consultation' },
            
            // Insurance Services
            { _id: '25', serviceName: 'Insurance', subServiceName: 'Life Insurance' },
            { _id: '26', serviceName: 'Insurance', subServiceName: 'Health Insurance' },
            { _id: '27', serviceName: 'Insurance', subServiceName: 'Vehicle Insurance' }
          ]
          console.log('Using default sub-services:', defaultSubServices);
          setSubServices(defaultSubServices)
          localStorage.setItem('subServices', JSON.stringify(defaultSubServices))
        }
      }

      // Load reminders
      const storedReminders = localStorage.getItem('reminders')
      if (storedReminders) {
        const parsedReminders = JSON.parse(storedReminders)
        console.log('Loaded reminders from localStorage:', parsedReminders);
        
        // Check if reminders have old dates, if so, clear and use new data
        const hasOldDates = parsedReminders.some(reminder => {
          const reminderDate = new Date(reminder.reminderDate)
          const today = new Date()
          const daysUntil = Math.ceil((reminderDate - today) / (1000 * 60 * 60 * 24))
          return daysUntil < 0 // If any reminder has past date
        })
        
        if (hasOldDates) {
          console.log('Found old reminder dates, clearing localStorage and using new data');
          localStorage.removeItem('reminders');
        } else {
          setReminders(parsedReminders)
        }
      }
      
      // Set default reminders if localStorage is empty or was cleared
      if (!localStorage.getItem('reminders')) {
        // Default reminders with future dates for testing alerts
        const today = new Date()
        const defaultReminders = [
          {
            id: 1,
            customerId: '1',
            customerName: 'John Doe',
            cellNo: '+1234567890',
            registerDate: today.toISOString().split('T')[0],
            services: ['Aadhaar Services'],
            subServices: ['Aadhaar Enrollment'],
            applicationNo: 'APP001',
            serviceStatus: 'pending',
            durationValue: '7',
            durationType: 'days',
            reminderDate: today.toISOString().split('T')[0], // Today
            notes: 'Follow up on Aadhaar enrollment'
          },
          {
            id: 2,
            customerId: '2',
            customerName: 'Jane Smith',
            cellNo: '+0987654321',
            registerDate: today.toISOString().split('T')[0],
            services: ['PAN Card'],
            subServices: ['PAN Card Application'],
            applicationNo: 'APP002',
            serviceStatus: 'applied',
            durationValue: '5',
            durationType: 'days',
            reminderDate: new Date(today.getTime() + 5 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], // 5 days from now
            notes: 'PAN card application follow-up'
          },
          {
            id: 3,
            customerId: '3',
            customerName: 'Mike Johnson',
            cellNo: '+1122334455',
            registerDate: new Date(today.getFullYear(), 3, 15).toISOString().split('T')[0], // April 15 (birthday)
            services: ['Passport'],
            subServices: ['Passport Application'],
            applicationNo: 'APP003',
            serviceStatus: 'pending',
            durationValue: '10',
            durationType: 'days',
            reminderDate: new Date(today.getFullYear(), 3, 15).toISOString().split('T')[0], // Birthday reminder
            notes: 'Birthday reminder - Special occasion'
          }
        ]
        console.log('Using default reminders with future dates:', defaultReminders);
        setReminders(defaultReminders)
        localStorage.setItem('reminders', JSON.stringify(defaultReminders))
      }
    } catch (error) {
      toast.error('Failed to fetch data')
      console.error('Error fetching data:', error)
    } finally {
      setLoading(false)
    }
  }

  const calculateReminderDate = () => {
    const registerDate = new Date(formData.registerDate)
    const duration = parseInt(formData.durationValue)
    
    if (!duration || isNaN(duration)) {
      setFormData(prev => ({ ...prev, reminderDate: '' }))
      return
    }

    let reminderDate = new Date(registerDate)
    
    switch (formData.durationType) {
      case 'days':
        reminderDate.setDate(registerDate.getDate() + duration)
        break
      case 'months':
        reminderDate.setMonth(registerDate.getMonth() + duration)
        break
      case 'years':
        reminderDate.setFullYear(registerDate.getFullYear() + duration)
        break
    }

    // Format as YYYY-MM-DD for date input
    const formattedDate = reminderDate.getFullYear() + '-' + 
      String(reminderDate.getMonth() + 1).padStart(2, '0') + '-' + 
      String(reminderDate.getDate()).padStart(2, '0')

    setFormData(prev => ({ 
      ...prev, 
      reminderDate: formattedDate
    }))
  }

  const handleCustomerSelect = (customer) => {
    setFormData(prev => ({
      ...prev,
      customerId: customer._id || customer.id,
      customerName: customer.name,
      cellNo: customer.cellNo || customer.phone || '',
      customerBirthday: customer.dateOfBirth || ''
    }))
    setCustomerSearch('')
    setShowCustomerList(false)
  }

  const handleServiceChange = (service, checked) => {
    if (checked) {
      setFormData(prev => ({
        ...prev,
        services: [...prev.services, service],
        subServices: [] // Clear sub-services when services change
      }))
    } else {
      setFormData(prev => ({
        ...prev,
        services: prev.services.filter(s => s !== service),
        subServices: [] // Clear sub-services when services change
      }))
    }
  }

  const handleSubServiceChange = (subService, checked) => {
    if (checked) {
      setFormData(prev => ({
        ...prev,
        subServices: [...prev.subServices, subService]
      }))
    } else {
      setFormData(prev => ({
        ...prev,
        subServices: prev.subServices.filter(s => s !== subService)
      }))
    }
  }

  const getAvailableSubServices = () => {
    console.log('Getting available sub-services...')
    console.log('Selected services:', formData.services)
    console.log('All sub-services:', subServices)
    
    if (!formData.services.length) {
      console.log('No services selected, returning empty array')
      return []
    }
    
    // Get the selected service object
    const selectedServiceName = formData.services[0]
    const selectedService = services.find(s => s.serviceName === selectedServiceName)
    
    if (!selectedService) {
      console.log('Selected service not found in services list')
      return []
    }
    
    console.log('Selected service object:', selectedService)
    
    // Filter sub-services based on selected serviceId
    const filtered = subServices.filter(sub => {
      // Handle both populated and non-populated serviceId
      const subServiceId = sub.serviceId?._id || sub.serviceId
      const matches = subServiceId === selectedService._id
      
      console.log('Checking sub-service:', sub.subServiceName, 'serviceId:', subServiceId, 'matches:', matches)
      return matches
    })
    
    console.log('Filtered sub-services:', filtered)
    return filtered
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    
    if (!formData.customerName || !formData.cellNo || !formData.durationValue) {
      toast.error('Please fill all required fields')
      return
    }

    try {
      const reminderData = {
        ...formData,
        id: editingReminder ? editingReminder.id : Date.now(),
        createdAt: editingReminder ? editingReminder.createdAt : new Date().toISOString()
      }

      if (editingReminder) {
        const updatedReminders = reminders.map(r => 
          r.id === editingReminder.id ? reminderData : r
        )
        setReminders(updatedReminders)
        localStorage.setItem('reminders', JSON.stringify(updatedReminders))
        toast.success('Reminder updated successfully')
      } else {
        const updatedReminders = [...reminders, reminderData]
        setReminders(updatedReminders)
        localStorage.setItem('reminders', JSON.stringify(updatedReminders))
        toast.success('Reminder created successfully')
      }
      
      resetForm()
    } catch (error) {
      toast.error('Failed to save reminder')
      console.error('Error saving reminder:', error)
    }
  }

  const resetForm = () => {
    setFormData({
      customerId: '',
      customerName: '',
      cellNo: '',
      customerBirthday: '',
      registerDate: new Date().toISOString().split('T')[0],
      services: [],
      subServices: [],
      applicationNo: '',
      serviceStatus: 'applied',
      durationValue: '',
      durationType: 'days',
      reminderDate: '',
      notes: ''
    })
    setEditingReminder(null)
    setShowForm(false)
    setCustomerSearch('')
    setShowCustomerList(false)
  }

  const handleEdit = (reminder) => {
    setEditingReminder(reminder)
    setFormData({
      customerId: reminder.customerId,
      customerName: reminder.customerName,
      cellNo: reminder.cellNo,
      customerBirthday: reminder.customerBirthday || '',
      registerDate: reminder.registerDate || new Date().toISOString().split('T')[0],
      services: reminder.services || [],
      subServices: reminder.subServices || [],
      applicationNo: reminder.applicationNo,
      serviceStatus: reminder.serviceStatus,
      durationValue: reminder.durationValue,
      durationType: reminder.durationType,
      reminderDate: reminder.reminderDate,
      notes: reminder.notes || ''
    })
    setShowForm(true)
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this reminder?')) {
      try {
        const updatedReminders = reminders.filter(r => r.id !== id)
        setReminders(updatedReminders)
        localStorage.setItem('reminders', JSON.stringify(updatedReminders))
        toast.success('Reminder deleted successfully')
      } catch (error) {
        toast.error('Failed to delete reminder')
        console.error('Error deleting reminder:', error)
      }
    }
  }

  const getStatusColor = (status) => {
    const statusOption = serviceStatusOptions.find(s => s.value === status)
    return statusOption ? statusOption.color : 'gray'
  }

  const getStatusBadge = (status) => {
    const color = getStatusColor(status)
    const colorClasses = {
      blue: 'bg-blue-100 text-blue-800',
      yellow: 'bg-yellow-100 text-yellow-800',
      green: 'bg-green-100 text-green-800',
      red: 'bg-red-100 text-red-800'
    }
    
    return (
      <span className={`px-2 py-1 text-xs font-medium rounded-full ${colorClasses[color] || 'bg-gray-100 text-gray-800'}`}>
        {status.charAt(0).toUpperCase() + status.slice(1)}
      </span>
    )
  }

  const filteredCustomers = customers.filter(customer =>
    customer.name.toLowerCase().includes(customerSearch.toLowerCase()) ||
    (customer.cellNo && customer.cellNo.includes(customerSearch)) ||
    (customer.phone && customer.phone.includes(customerSearch))
  )

  const filteredReminders = reminders.filter(reminder =>
    reminder.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    reminder.cellNo.includes(searchTerm) ||
    reminder.applicationNo.toLowerCase().includes(searchTerm) ||
    (reminder.services && reminder.services.some(s => s.toLowerCase().includes(searchTerm.toLowerCase())))
  )

  // Calculate alert cards based on filter
  const getAlertCards = () => {
    const today = new Date()
    const todayString = today.toISOString().split('T')[0]
    
    console.log('=== ALERT CARDS DEBUG ===');
    console.log('Today:', todayString);
    console.log('Alert Filter:', alertFilter);
    console.log('All reminders:', reminders);
    
    let filteredReminders = []
    
    if (alertFilter === 'today' || alertFilter === 'all') {
      // Get today's reminders
      const todayReminders = reminders.filter(reminder => {
        const isToday = reminder.reminderDate === todayString
        const isNotCompleted = reminder.serviceStatus !== 'completed'
        console.log('Today check - Reminder:', reminder.customerName, 'Date:', reminder.reminderDate, 'Is today:', isToday, 'Not completed:', isNotCompleted);
        return isToday && isNotCompleted
      })
      filteredReminders.push(...todayReminders)
    }
    
    if (alertFilter === 'birthday' || alertFilter === 'all') {
      // Get birthday reminders (assume April 15 as example birthday)
      const birthdayReminders = reminders.filter(reminder => {
        const reminderDate = new Date(reminder.reminderDate)
        const isBirthday = reminderDate.getMonth() === 3 && reminderDate.getDate() === 15 // April 15
        const isNotCompleted = reminder.serviceStatus !== 'completed'
        console.log('Birthday check - Reminder:', reminder.customerName, 'Date:', reminder.reminderDate, 'Is birthday:', isBirthday, 'Not completed:', isNotCompleted);
        return isBirthday && isNotCompleted
      })
      filteredReminders.push(...birthdayReminders)
    }
    
    // Remove duplicates
    const uniqueReminders = filteredReminders.filter((reminder, index, self) => 
      index === self.findIndex(r => r.id === reminder.id)
    )
    
    console.log('Filtered reminders for alerts:', uniqueReminders);
    return uniqueReminders
  }

  const getAlertType = (reminder) => {
    const today = new Date()
    const todayString = today.toISOString().split('T')[0]
    const reminderDate = new Date(reminder.reminderDate)
    
    if (reminder.reminderDate === todayString) {
      return 'today'
    }
    
    if (reminderDate.getMonth() === 3 && reminderDate.getDate() === 15) { // April 15
      return 'birthday'
    }
    
    return 'regular'
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-4 lg:p-6 bg-gray-50 min-h-screen space-y-4 sm:space-y-6">
      {/* Service Reminders Table */}
      <div>
        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3 mb-3 sm:mb-4">
          <h3 className="text-base sm:text-lg font-semibold text-gray-800 flex items-center gap-2">
            <Calendar className="h-4 w-4 sm:h-5 sm:w-5 text-blue-500" />
            Service Reminders
          </h3>
          <div className="flex flex-wrap gap-1 sm:gap-2">
            <button
              onClick={() => setAlertFilter('today')}
              className={`px-2 sm:px-3 py-1 sm:py-1.5 rounded-lg text-xs sm:text-sm font-medium transition-colors ${
                alertFilter === 'today' 
                  ? 'bg-blue-600 text-white' 
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              Today
            </button>
            <button
              onClick={() => setAlertFilter('birthday')}
              className={`px-2 sm:px-3 py-1 sm:py-1.5 rounded-lg text-xs sm:text-sm font-medium transition-colors ${
                alertFilter === 'birthday' 
                  ? 'bg-pink-600 text-white' 
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              Birthday
            </button>
            <button
              onClick={() => setAlertFilter('all')}
              className={`px-2 sm:px-3 py-1 sm:py-1.5 rounded-lg text-xs sm:text-sm font-medium transition-colors ${
                alertFilter === 'all' 
                  ? 'bg-green-600 text-white' 
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              All
            </button>
          </div>
        </div>
        
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Customer
                </th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Phone
                </th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Service
                </th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Application
                </th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Date
                </th>
                <th className="px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Type
                </th>
                <th className="px-4 py-2 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {getAlertCards().length > 0 ? (
                getAlertCards().map((reminder) => {
                  const alertType = getAlertType(reminder)
                  return (
                    <tr key={reminder.id} className={
                      alertType === 'today' ? 'bg-gradient-to-r from-blue-50 to-blue-100 border-l-4 border-blue-500' : 
                      alertType === 'birthday' ? 'bg-gradient-to-r from-pink-50 to-pink-100 border-l-4 border-pink-500' : 
                      'hover:bg-gray-50'
                    }>
                      <td className="px-4 py-3">
                        <div className="font-medium text-gray-900 text-sm">{reminder.customerName}</div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="text-sm text-gray-600">{reminder.cellNo}</div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="text-sm text-gray-600">{reminder.services?.join(', ') || 'N/A'}</div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="text-sm text-gray-600">{reminder.applicationNo || 'N/A'}</div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="text-sm text-gray-600">{reminder.reminderDate}</div>
                      </td>
                      <td className="px-4 py-3">
                        <span className={`inline-flex items-center gap-1 px-3 py-1.5 text-xs font-semibold rounded-full shadow-sm ${
                          alertType === 'today' 
                            ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-blue-200' 
                            : alertType === 'birthday'
                            ? 'bg-gradient-to-r from-pink-500 to-pink-600 text-white shadow-pink-200'
                            : 'bg-gray-200 text-gray-700'
                        }`}>
                          {alertType === 'today' ? (
                            <>
                              <AlertTriangle className="h-3 w-3" />
                              Today
                            </>
                          ) : alertType === 'birthday' ? (
                            <>
                              <Cake className="h-3 w-3" />
                              Birthday
                            </>
                          ) : (
                            <>
                              <AlertTriangle className="h-3 w-3" />
                              Reminder
                            </>
                          )}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-right">
                        <div className="flex justify-end gap-2">
                          <button
                            onClick={() => handleEdit(reminder)}
                            className={`p-1.5 rounded-lg transition-colors ${
                              alertType === 'today' 
                                ? 'text-blue-700 hover:bg-blue-200' 
                                : alertType === 'birthday'
                                ? 'text-pink-700 hover:bg-pink-200'
                                : 'text-blue-600 hover:bg-gray-100'
                            }`}
                            title="Edit"
                          >
                            <Edit2 size={14} />
                          </button>
                          <button
                            onClick={() => handleDelete(reminder.id)}
                            className={`p-1.5 rounded-lg transition-colors ${
                              alertType === 'today' 
                                ? 'text-red-700 hover:bg-red-200' 
                                : alertType === 'birthday'
                                ? 'text-red-700 hover:bg-red-200'
                                : 'text-red-600 hover:bg-gray-100'
                            }`}
                            title="Delete"
                          >
                            <Trash2 size={14} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  )
                })
              ) : (
                <tr>
                  <td colSpan="7" className="px-4 py-8 text-center">
                    <Calendar className="mx-auto text-gray-400" size={32} />
                    <p className="mt-2 text-sm text-gray-500">
                      {alertFilter === 'today' ? 'No reminders for today' : 
                       alertFilter === 'birthday' ? 'No birthday reminders' : 
                       'No service reminders found'}
                    </p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Service Reminders</h1>
          <p className="text-gray-600 mt-1">Manage customer service reminders and follow-ups</p>
        </div>
        <button
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
        >
          <Plus size={20} />
          Add Reminder
        </button>
      </div>

      {/* Search */}
      <div className="bg-white rounded-lg shadow p-4">
        <div className="relative">
          <Search className="absolute left-3 top-3 text-gray-400" size={20} />
          <input
            type="text"
            placeholder="Search reminders by customer, phone, or application..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          />
        </div>
      </div>

      {/* Reminders Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Customer
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Application No
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Services
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Status
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Duration
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Reminder Date
              </th>
              <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {filteredReminders.map((reminder) => (
              <tr key={reminder.id}>
                <td className="px-6 py-4">
                  <div>
                    <div className="font-medium text-gray-900">{reminder.customerName}</div>
                    <div className="text-sm text-gray-500">{reminder.cellNo}</div>
                  </div>
                </td>
                <td className="px-6 py-4 text-gray-900">
                  {reminder.applicationNo}
                </td>
                <td className="px-6 py-4">
                  <div className="text-sm">
                    {reminder.services && reminder.services.length > 0 ? (
                      <div className="space-y-1">
                        {reminder.services.slice(0, 2).map((service, idx) => (
                          <div key={idx} className="text-gray-600">• {service}</div>
                        ))}
                        {reminder.services.length > 2 && (
                          <div className="text-gray-400">+{reminder.services.length - 2} more</div>
                        )}
                      </div>
                    ) : (
                      <span className="text-gray-400">No services</span>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4">
                  {getStatusBadge(reminder.serviceStatus)}
                </td>
                <td className="px-6 py-4 text-gray-900">
                  {reminder.durationValue} {reminder.durationType}
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2">
                    <Calendar size={16} className="text-gray-400" />
                    <span className="text-gray-900">{reminder.reminderDate}</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button
                      onClick={() => handleEdit(reminder)}
                      className="text-blue-600 hover:text-blue-800 transition-colors"
                      title="Edit"
                    >
                      <Edit2 size={18} />
                    </button>
                    <button
                      onClick={() => handleDelete(reminder.id)}
                      className="text-red-600 hover:text-red-800 transition-colors"
                      title="Delete"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        
        {filteredReminders.length === 0 && (
          <div className="text-center py-8">
            <Calendar className="mx-auto text-gray-400" size={48} />
            <p className="mt-2 text-gray-500">No reminders found</p>
          </div>
        )}
      </div>

      {/* Add/Edit Reminder Modal */}
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-7xl max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-gray-200">
              <h2 className="text-xl font-bold text-gray-900">
                {editingReminder ? 'Edit Reminder' : 'Add New Reminder'}
              </h2>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              {/* Customer Selection */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-3">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Customer Search *
                  </label>
                  <div className="relative">
                    <div className="relative">
                      <Search className="absolute left-3 top-3 text-gray-400" size={20} />
                      <input
                        type="text"
                        value={customerSearch}
                        onChange={(e) => {
                          setCustomerSearch(e.target.value)
                          setShowCustomerList(true)
                        }}
                        onFocus={() => setShowCustomerList(true)}
                        placeholder="Search customer by name or phone..."
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                      />
                    </div>
                    
                    {showCustomerList && customerSearch && (
                      <div className="absolute z-10 w-full mt-1 bg-white border border-gray-300 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                        {filteredCustomers.length > 0 ? (
                          filteredCustomers.map(customer => (
                            <div
                              key={customer._id || customer.id}
                              onClick={() => handleCustomerSelect(customer)}
                              className="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 last:border-b-0"
                            >
                              <div className="font-medium text-gray-900">{customer.name}</div>
                              <div className="text-sm text-gray-500">
                                {customer.cellNo || customer.phone || 'No phone'}
                              </div>
                              <div className="text-xs text-gray-400">
                                ID: {customer.customerId || customer._id}
                                {customer.dateOfBirth && ` • DOB: ${customer.dateOfBirth}`}
                              </div>
                            </div>
                          ))
                        ) : (
                          <div className="px-4 py-3 text-gray-500">No customers found</div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Customer Name *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.customerName}
                    onChange={(e) => setFormData({ ...formData, customerName: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Customer name"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Cell Number *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.cellNo}
                    onChange={(e) => setFormData({ ...formData, cellNo: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Phone number"
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Customer Birthday
                  </label>
                  <input
                    type="date"
                    value={formData.customerBirthday || ''}
                    onChange={(e) => setFormData({ ...formData, customerBirthday: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    placeholder="Customer birthday"
                  />
                </div>
              </div>

              {/* Reminder Details Table */}
              <div>
                <h3 className="text-lg font-semibold text-gray-800 mb-3">Reminder Details</h3>
                <div className="overflow-x-auto">
                  <table className="w-full border-collapse border border-gray-300">
                    <thead>
                      <tr className="bg-gray-100">
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Reg Date</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Service Name</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Sub-Service Name</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Application No</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Duration</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Reminder Date</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Service Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr>
                        <td className="border border-gray-300 px-3 py-2">
                          <input
                            type="date"
                            value={formData.registerDate || new Date().toISOString().split('T')[0]}
                            onChange={(e) => setFormData({ ...formData, registerDate: e.target.value })}
                            className="w-full px-2 py-1 border border-gray-200 rounded text-sm"
                          />
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <select
                            value={formData.services.length > 0 ? formData.services[0] : ''}
                            onChange={(e) => {
                              const selectedService = e.target.value;
                              console.log('=== SERVICE SELECTION DEBUG ===');
                              console.log('Selected service:', selectedService);
                              console.log('Available services:', services.map(s => s.serviceName));
                              console.log('Available sub-services:', subServices.map(s => ({ serviceName: s.serviceName, subServiceName: s.subServiceName })));
                              
                              if (selectedService) {
                                setFormData(prev => ({
                                  ...prev,
                                  services: [selectedService],
                                  subServices: [] // Clear sub-services when service changes
                                }));
                              } else {
                                setFormData(prev => ({
                                  ...prev,
                                  services: [],
                                  subServices: []
                                }));
                              }
                            }}
                            className="w-full px-2 py-1 border border-gray-200 rounded text-sm"
                          >
                            <option value="">Select Service</option>
                            {services.map(service => (
                              <option key={service._id} value={service.serviceName}>
                                {service.serviceName}
                              </option>
                            ))}
                          </select>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <select
                            value={formData.subServices.length > 0 ? formData.subServices[0] : ''}
                            onChange={(e) => {
                              const selectedSubService = e.target.value;
                              console.log('=== SUB-SERVICE SELECTION DEBUG ===');
                              console.log('Selected sub-service:', selectedSubService);
                              console.log('Available sub-services:', getAvailableSubServices());
                              
                              if (selectedSubService) {
                                setFormData(prev => ({
                                  ...prev,
                                  subServices: [selectedSubService]
                                }));
                              } else {
                                setFormData(prev => ({
                                  ...prev,
                                  subServices: []
                                }));
                              }
                            }}
                            className="w-full px-2 py-1 border border-gray-200 rounded text-sm"
                            disabled={!formData.services.length}
                          >
                            <option value="">Select Sub-Service</option>
                            {getAvailableSubServices().map(subService => (
                              <option key={subService._id} value={subService.subServiceName}>
                                {subService.subServiceName}
                              </option>
                            ))}
                          </select>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <input
                            type="text"
                            value={formData.applicationNo}
                            onChange={(e) => {
                              // Allow only uppercase letters and convert to uppercase
                              const value = e.target.value.toUpperCase().replace(/[^A-Z]/g, '');
                              setFormData({ ...formData, applicationNo: value });
                            }}
                            onKeyPress={(e) => {
                              // Allow only letters
                              const char = String.fromCharCode(e.which);
                              if (!/[a-zA-Z]/.test(char)) {
                                e.preventDefault();
                              }
                            }}
                            className="w-full px-2 py-1 border border-gray-200 rounded text-sm uppercase"
                            placeholder="Application number"
                            maxLength={4}
                          />
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <div className="flex gap-1">
                            <input
                              type="number"
                              required
                              min="1"
                              value={formData.durationValue}
                              onChange={(e) => setFormData({ ...formData, durationValue: e.target.value })}
                              className="w-16 px-2 py-1 border border-gray-200 rounded text-sm text-center"
                              placeholder="7"
                            />
                            <select
                              value={formData.durationType}
                              onChange={(e) => setFormData({ ...formData, durationType: e.target.value })}
                              className="flex-1 px-2 py-1 border border-gray-200 rounded text-sm"
                            >
                              {durationTypes.map(type => (
                                <option key={type.value} value={type.value}>
                                  {type.label}
                                </option>
                              ))}
                            </select>
                          </div>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <div className="flex items-center gap-2">
                            <Calendar size={16} className="text-gray-400" />
                            <input
                              type="date"
                              value={formData.reminderDate}
                              readOnly
                              className="flex-1 px-2 py-1 border border-gray-200 rounded bg-gray-50 text-sm"
                            />
                          </div>
                        </td>
                        <td className="border border-gray-300 px-3 py-2">
                          <select
                            value={formData.serviceStatus}
                            onChange={(e) => setFormData({ ...formData, serviceStatus: e.target.value })}
                            className="w-full px-2 py-1 border border-gray-200 rounded text-sm"
                          >
                            {serviceStatusOptions.map(status => (
                              <option key={status.value} value={status.value}>
                                {status.label}
                              </option>
                            ))}
                          </select>
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Notes */}
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Notes
                </label>
                <textarea
                  value={formData.notes}
                  onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  rows="3"
                  placeholder="Additional notes..."
                />
              </div>
            </form>
            
            <div className="p-6 border-t border-gray-200 flex justify-end gap-3">
              <button
                onClick={resetForm}
                className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              >
                {editingReminder ? 'Update' : 'Save'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default Reminder
