import React, { useState, useEffect } from 'react'
import { Search, Plus, Trash2, Save, Printer, User, Phone, Calendar, FileText, X, Edit2, Eye, Package, Calculator, TrendingUp, AlertCircle } from 'lucide-react'
import { useServicesData } from '../services/servicesData'
import { customersAPI, billsAPI } from '../services/api'
import { toast } from 'react-hot-toast'

const NewBill = () => {
  const [customers, setCustomers] = useState([])
  const [selectedCustomer, setSelectedCustomer] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [billDate, setBillDate] = useState(new Date().toISOString().split('T')[0])
  const [billNo, setBillNo] = useState('')
  const [billItems, setBillItems] = useState([])
  const [serviceCharges, setServiceCharges] = useState(0)
  const [discount, setDiscount] = useState(0)
  const [showCustomerSearch, setShowCustomerSearch] = useState(false)
  const [paymentMethod, setPaymentMethod] = useState('cash')
  const [transactionNo, setTransactionNo] = useState('')
  const [upiId, setUpiId] = useState('')
  const [notes, setNotes] = useState('')
  const [customerType, setCustomerType] = useState('cash')
  const billingMode = 'stock' // Only stock billing mode
  const [stockItems, setStockItems] = useState([])
  const [stockCategories, setStockCategories] = useState([])
  const [isSaving, setIsSaving] = useState(false)

  // Use shared services data service
  const { services, subServices, loading, getSubServicesForService } = useServicesData()

  // Generate bill number on component mount
  useEffect(() => {
    const today = new Date()
    const year = today.getFullYear()
    const month = String(today.getMonth() + 1).padStart(2, '0')
    const day = String(today.getDate()).padStart(2, '0')
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0')
    setBillNo(`BILL-${year}${month}${day}-${random}`)
  }, [])

  // Load Stock Management categories
  useEffect(() => {
    const loadStockCategories = async () => {
      try {
        const token = localStorage.getItem('authToken')
        const response = await fetch('http://localhost:5001/api/stock-management/categories', {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        })
        
        if (response.ok) {
          const categories = await response.json()
          localStorage.setItem('stockCategories', JSON.stringify(categories))
          setStockCategories(categories)
        } else {
          const savedCategories = localStorage.getItem('stockCategories')
          if (savedCategories) {
            setStockCategories(JSON.parse(savedCategories))
          }
        }
      } catch (error) {
        console.error('Error loading stock categories:', error)
        const savedCategories = localStorage.getItem('stockCategories')
        if (savedCategories) {
          setStockCategories(JSON.parse(savedCategories))
        }
      }
    }
    
    loadStockCategories()
  }, [])

  // Load stock items
  useEffect(() => {
    const loadStockItems = async () => {
      try {
        const token = localStorage.getItem('authToken')
        const response = await fetch('http://localhost:5001/api/stock-management/items', {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        })
        
        if (response.ok) {
          const items = await response.json()
          localStorage.setItem('stockManagement', JSON.stringify(items))
          setStockItems(items)
        } else {
          const savedStock = localStorage.getItem('stockManagement')
          if (savedStock) {
            setStockItems(JSON.parse(savedStock))
          }
        }
      } catch (error) {
        console.error('Error loading stock items:', error)
        const savedStock = localStorage.getItem('stockManagement')
        if (savedStock) {
          setStockItems(JSON.parse(savedStock))
        }
      }
    }
    
    loadStockItems()
  }, [])

  // Fetch customers
  useEffect(() => {
    const fetchCustomers = async () => {
      try {
        const response = await customersAPI.getAll()
        const data = response.data
        setCustomers(data)
      } catch (error) {
        console.error('Error fetching customers:', error)
        const savedCustomers = localStorage.getItem('customers')
        if (savedCustomers) {
          setCustomers(JSON.parse(savedCustomers))
        }
      }
    }
    fetchCustomers()
  }, [])

  // Auto-calculate totals when items change
  useEffect(() => {
    calculateTotals()
  }, [billItems, serviceCharges, discount])

  // Filter customers based on search
  const filteredCustomers = customers.filter(customer =>
    customer.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    customer.cellNo.includes(searchTerm) ||
    customer.customerId.toLowerCase().includes(searchTerm.toLowerCase())
  )

  // Add new bill item with enhanced auto-calculation
  const addBillItem = () => {
    const newItem = {
      id: Date.now(),
      serviceId: null,
      subServiceId: null,
      serviceName: '',
      subServiceName: '',
      quantity: 1,
      unitPrice: 0,
      unit: 'unit',
      amount: 0,
      // Stock detail fields
      category: '',
      subCategory: '',
      totalStock: 0,
      // Enhanced counting fields for Sheets-Wastage calculation
      sheetCount: 0,
      wastCount: 0,
      totalCount: 0,
      // Additional fields for better tracking
      text: '',
      rate: 0,
      gst: 0,
      totalWithGst: 0
    }
    
    setBillItems([...billItems, newItem])
    toast.success('Item added to bill')
  }

  // Update bill item with intelligent auto-calculation
  const updateBillItem = (id, field, value) => {
    const updatedItems = billItems.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        
                
        // Handle category changes
        if (field === 'category') {
          updatedItem.subCategory = ''
          updatedItem.totalStock = 0
          updatedItem.unitPrice = 0
        }
        
        // Handle sub-category changes with price lookup
        if (field === 'subCategory' && updatedItem.category) {
          const stockInfo = getStockInfo(updatedItem.category, value)
          updatedItem.unitPrice = stockInfo.unitPrice || 0
          updatedItem.totalStock = stockInfo.currentStock || 0
          updatedItem.unit = stockInfo.unit || 'unit'
        }
        
        // Auto-calculate quantity when sheetCount or wastCount changes (Sheets - Wastage = Quantity)
        if (field === 'sheetCount' || field === 'wastCount') {
          const sheets = parseFloat(updatedItem.sheetCount) || 0
          const wast = parseFloat(updatedItem.wastCount) || 0
          const calculatedQty = sheets - wast
          
          // Ensure quantity doesn't go negative
          updatedItem.totalCount = Math.max(0, calculatedQty)
          updatedItem.quantity = Math.max(0, calculatedQty)
          
          console.log(`Quantity Calculation: ${sheets} sheets - ${wast} wastage = ${updatedItem.quantity} quantity`)
        }
        
        // Handle quantity changes
        if (field === 'quantity') {
          const qty = parseFloat(value) || 0
          updatedItem.totalCount = qty
          // Distribute quantity between sheets and wastage if possible
          if (qty > 0 && updatedItem.sheetCount === 0 && updatedItem.wastCount === 0) {
            updatedItem.sheetCount = qty
            updatedItem.wastCount = 0
          }
        }
        
        // Handle rate changes (alternative to unitPrice)
        if (field === 'rate') {
          updatedItem.unitPrice = parseFloat(value) || 0
        }
        
        // Calculate GST and total with GST
        if (field === 'gst') {
          const gstRate = parseFloat(value) || 0
          const amount = updatedItem.quantity * updatedItem.unitPrice
          updatedItem.totalWithGst = amount + (amount * gstRate / 100)
        }
        
        // Auto-calculate amount and total with GST
        const quantity = parseFloat(updatedItem.quantity) || 0
        const unitPrice = parseFloat(updatedItem.unitPrice) || 0
        const gstRate = parseFloat(updatedItem.gst) || 0
        
        updatedItem.amount = quantity * unitPrice
        updatedItem.totalWithGst = updatedItem.amount + (updatedItem.amount * gstRate / 100)
        
        return updatedItem
      }
      return item
    })
    
    setBillItems(updatedItems)
  }

  // Remove bill item
  const removeBillItem = (id) => {
    setBillItems(billItems.filter(item => item.id !== id))
    toast.success('Item removed from bill')
  }

  // Calculate totals with enhanced breakdown
  const calculateTotals = () => {
    const subtotal = billItems.reduce((sum, item) => sum + (item.amount || 0), 0)
    const totalGst = billItems.reduce((sum, item) => {
      const amount = item.amount || 0
      const gstRate = parseFloat(item.gst) || 0
      return sum + (amount * gstRate / 100)
    }, 0)
    const serviceChargesAmount = parseFloat(serviceCharges) || 0
    const discountAmount = parseFloat(discount) || 0
    const grandTotal = subtotal + totalGst + serviceChargesAmount - discountAmount
    
    return { subtotal, totalGst, grandTotal }
  }

  // Get stock info helper
  const getStockInfo = (category, subCategory) => {
    const allStockItems = [...stockItems]
    
    // Add categories from Settings
    if (stockCategories.length > 0) {
      stockCategories.forEach(category => {
        if (category.isActive && category.subcategories) {
          category.subcategories.forEach(sub => {
            if (sub.isActive !== false) {
              allStockItems.push({
                category: category.name,
                subCategory: sub.name,
                currentStock: 0,
                unitPrice: sub.unitPrice || 0,
                unit: sub.unit || 'unit'
              })
            }
          })
        }
      })
    }
    
    const matchingItem = allStockItems.find(item => 
      item.category === category && item.subCategory === subCategory
    )
    
    return matchingItem || {
      currentStock: 0,
      unitPrice: 0,
      unit: 'unit'
    }
  }

  // Get unique categories
  const getUniqueCategories = () => {
    const allStockItems = [...stockItems]
    
    if (stockCategories.length > 0) {
      stockCategories.forEach(category => {
        if (category.isActive && category.subcategories) {
          category.subcategories.forEach(sub => {
            if (sub.isActive !== false) {
              allStockItems.push({
                category: category.name,
                subCategory: sub.name
              })
            }
          })
        }
      })
    }
    
    const categories = [...new Set(allStockItems.map(item => item.category).filter(Boolean))]
    return categories.sort()
  }

  // Get sub-categories for category
  const getSubCategoriesForCategory = (category) => {
    const allStockItems = [...stockItems]
    
    if (stockCategories.length > 0) {
      stockCategories.forEach(cat => {
        if (cat.isActive && cat.subcategories && cat.name === category) {
          cat.subcategories.forEach(sub => {
            if (sub.isActive !== false) {
              allStockItems.push({
                category: cat.name,
                subCategory: sub.name
              })
            }
          })
        }
      })
    }
    
    const subCategories = [...new Set(allStockItems
      .filter(item => item.category === category)
      .map(item => item.subCategory)
      .filter(Boolean)
    )]
    
    return subCategories.sort()
  }

  // Select customer
  const selectCustomer = (customer) => {
    setSelectedCustomer(customer)
    setShowCustomerSearch(false)
    setSearchTerm('')
    toast.success(`Customer selected: ${customer.name}`)
  }

  // Save bill with validation
  const saveBill = async () => {
    if (!selectedCustomer || billItems.length === 0) {
      toast.error('Please select a customer and add at least one item')
      return
    }

    // Validate items (stock billing only)
    const invalidItems = billItems.filter(item => {
      return !item.category || !item.subCategory || item.totalCount <= 0
    })

    if (invalidItems.length > 0) {
      toast.error('Please fill in all required fields for bill items')
      return
    }

    setIsSaving(true)

    try {
      const totals = calculateTotals()
      
      const billData = {
        billNo,
        customerId: selectedCustomer._id,
        customerName: selectedCustomer.name,
        customerAddress: selectedCustomer.address || '',
        billDate: new Date(billDate),
        subtotal: totals.subtotal,
        serviceCharges: parseFloat(serviceCharges) || 0,
        discount: parseFloat(discount) || 0,
        grandTotal: totals.grandTotal,
        paymentMethod,
        customerType,
        transactionNo,
        upiId,
        notes,
        status: 'pending'
      }

      const itemsData = billItems.map(item => ({
        serviceId: null,
        subServiceId: null,
        serviceName: '',
        subServiceName: '',
        quantity: parseFloat(item.quantity) || 0,
        unitPrice: parseFloat(item.unitPrice) || 0,
        unit: item.unit || 'unit',
        amount: parseFloat(item.amount) || 0,
        category: item.category || '',
        subCategory: item.subCategory || '',
        totalStock: parseFloat(item.totalStock) || 0,
        sheetCount: parseFloat(item.sheetCount) || 0,
        wastCount: parseFloat(item.wastCount) || 0,
        totalCount: parseFloat(item.totalCount) || 0,
        text: item.text || '',
        gst: parseFloat(item.gst) || 0
      }))

      // Try to save via API first
      try {
        await billsAPI.create({ bill: billData, items: itemsData })
        toast.success('Bill saved successfully!')
        
        // Reset form
        resetForm()
      } catch (apiError) {
        console.log('API failed, saving to localStorage:', apiError)
        
        // Fallback to localStorage
        const existingBills = JSON.parse(localStorage.getItem('bills') || '[]')
        const newBill = {
          ...billData,
          _id: Date.now().toString(),
          items: itemsData,
          createdAt: new Date().toISOString()
        }
        
        existingBills.push(newBill)
        localStorage.setItem('bills', JSON.stringify(existingBills))
        
        toast.success('Bill saved locally (demo mode)')
        resetForm()
      }
    } catch (error) {
      console.error('Error saving bill:', error)
      toast.error('Failed to save bill')
    } finally {
      setIsSaving(false)
    }
  }

  // Reset form
  const resetForm = () => {
    setSelectedCustomer(null)
    setBillItems([])
    setServiceCharges(0)
    setDiscount(0)
    setSearchTerm('')
    setPaymentMethod('cash')
    setTransactionNo('')
    setUpiId('')
    setNotes('')
    setCustomerType('cash')
    
    // Generate new bill number
    const today = new Date()
    const year = today.getFullYear()
    const month = String(today.getMonth() + 1).padStart(2, '0')
    const day = String(today.getDate()).padStart(2, '0')
    const random = Math.floor(Math.random() * 1000).toString().padStart(3, '0')
    setBillNo(`BILL-${year}${month}${day}-${random}`)
  }

  // Get current totals
  const totals = calculateTotals()

  return (
    <div className="h-screen overflow-y-auto p-4 sm:p-6 max-w-7xl mx-auto">
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 sm:p-6 mb-6">
        {/* Responsive Header */}
        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start mb-6 space-y-4 sm:space-y-0">
          <div>
            <h1 className="text-xl sm:text-2xl font-bold text-gray-900">Create New Bill</h1>
            <p className="text-xs sm:text-sm text-gray-600 mt-1">Generate bills with automatic quantity calculation (Sheets - Wastage = Quantity)</p>
          </div>
          <div className="flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-2">
            <button
              onClick={() => window.print()}
              className="flex items-center justify-center px-3 sm:px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 text-sm sm:text-base"
            >
              <Printer className="h-4 w-4 sm:mr-2" />
              <span className="hidden sm:inline">Print</span>
              <span className="sm:hidden">Print</span>
            </button>
            <button
              onClick={saveBill}
              disabled={isSaving}
              className="flex items-center justify-center px-3 sm:px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 text-sm sm:text-base"
            >
              <Save className="h-4 w-4 sm:mr-2" />
              {isSaving ? 'Saving...' : 'Save Bill'}
            </button>
          </div>
        </div>

        {/* Bill Header */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6 mb-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Bill Number</label>
            <input
              type="text"
              value={billNo}
              onChange={(e) => setBillNo(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg bg-gray-50 text-sm"
              readOnly
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Bill Date</label>
            <input
              type="date"
              value={billDate}
              onChange={(e) => setBillDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            />
          </div>
        </div>

        {/* Customer Selection */}
        <div className="mb-6">
          <label className="block text-sm font-medium text-gray-700 mb-2">Customer Search</label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4 sm:h-5 sm:w-5" />
            <input
              type="text"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onFocus={() => setShowCustomerSearch(true)}
              placeholder="Search customer by name, ID, or phone..."
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
            />
          </div>

          {showCustomerSearch && filteredCustomers.length > 0 && (
            <div className="absolute z-10 mt-1 w-full bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-y-auto">
              {filteredCustomers.map((customer) => (
                <div
                  key={customer._id}
                  onClick={() => selectCustomer(customer)}
                  className="px-3 sm:px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-100 last:border-b-0"
                >
                  <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between">
                    <div>
                      <div className="font-medium text-gray-900 text-sm">{customer.name}</div>
                      <div className="text-xs sm:text-sm text-gray-500">{customer.cellNo}</div>
                    </div>
                    <div className="text-xs sm:text-sm text-gray-500 mt-1 sm:mt-0">{customer.customerId}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Selected Customer Info */}
        {selectedCustomer && (
          <div className="mb-6 p-4 bg-blue-50 rounded-lg">
            <div className="flex items-center justify-between">
              <div>
                <p className="font-medium text-gray-900">{selectedCustomer.name}</p>
                <p className="text-sm text-gray-600">{selectedCustomer.cellNo}</p>
              </div>
              <button
                onClick={() => {
                  setSelectedCustomer(null)
                  setSearchTerm('')
                }}
                className="text-gray-400 hover:text-gray-600"
              >
                <X className="h-4 w-4" />
              </button>
            </div>
          </div>
        )}

        {/* Bill Items Table */}
        <div className="mb-6">
          <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start mb-4 space-y-3 sm:space-y-0">
            <h3 className="text-lg font-medium text-gray-900">Bill Particulars</h3>
            <button
              onClick={addBillItem}
              className="flex items-center justify-center px-3 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm"
            >
              <Plus className="h-4 w-4 mr-2" />
              Add Item
            </button>
          </div>

          {billItems.length > 0 && (
            <div className="overflow-x-auto">
              {/* Mobile View - Card Layout */}
              <div className="sm:hidden space-y-3">
                {billItems.map((item, index) => (
                  <div key={item.id} className="bg-white border border-gray-200 rounded-lg p-3">
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex-1">
                        <div className="text-sm font-medium text-gray-900">{item.category || 'No category'}</div>
                        <div className="text-xs text-gray-500">{item.subCategory || 'No sub-category'}</div>
                      </div>
                      <button
                        onClick={() => removeBillItem(item.id)}
                        className="text-red-600 hover:text-red-900 ml-2"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                    <div className="grid grid-cols-2 gap-2 text-xs">
                      <div>
                        <label className="text-gray-500">Sheets:</label>
                        <input
                          type="number"
                          value={item.sheetCount}
                          onChange={(e) => updateBillItem(item.id, 'sheetCount', e.target.value)}
                          min="0"
                          className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                        />
                      </div>
                      <div>
                        <label className="text-gray-500">Wastage:</label>
                        <input
                          type="number"
                          value={item.wastCount}
                          onChange={(e) => updateBillItem(item.id, 'wastCount', e.target.value)}
                          min="0"
                          className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                        />
                      </div>
                      <div>
                        <label className="text-gray-500">Rate:</label>
                        <input
                          type="number"
                          value={item.unitPrice}
                          onChange={(e) => updateBillItem(item.id, 'unitPrice', e.target.value)}
                          min="0"
                          step="0.01"
                          className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                        />
                      </div>
                      <div>
                        <label className="text-gray-500">GST %:</label>
                        <input
                          type="number"
                          value={item.gst}
                          onChange={(e) => updateBillItem(item.id, 'gst', e.target.value)}
                          min="0"
                          max="100"
                          step="0.1"
                          className="w-full px-2 py-1 border border-gray-300 rounded text-xs"
                        />
                      </div>
                      <div className="col-span-2">
                        <label className="text-gray-500">Quantity: {item.totalCount}</label>
                        <div className={`text-xs px-2 py-1 rounded font-medium ${
                          item.wastCount > item.sheetCount 
                            ? 'bg-red-50 border border-red-200 text-red-700' 
                            : 'bg-blue-50 border border-blue-200 text-blue-700'
                        }`}>
                          {item.sheetCount} - {item.wastCount} = {item.totalCount}
                          {item.wastCount > item.sheetCount && (
                            <div className="text-xs font-medium mt-1">Wastage exceeds sheets!</div>
                          )}
                        </div>
                      </div>
                      <div className="col-span-2">
                        <label className="text-gray-500">Amount:</label>
                        <div className="w-full px-2 py-1 text-sm bg-gray-50 border border-gray-300 rounded font-medium">
                          Rs. {item.amount.toFixed(2)}
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              
              {/* Desktop View - Table Layout */}
              <table className="hidden sm:table min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-2 sm:px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">
                      Category
                    </th>
                    <th className="px-2 sm:px-4 py-2 text-left text-xs font-medium text-gray-500 uppercase">
                      Sub Category
                    </th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Sheets</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Wastage</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Qty</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Rate</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">GST %</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Amount</th>
                    <th className="px-2 sm:px-4 py-2 text-center text-xs font-medium text-gray-500 uppercase">Actions</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {billItems.map((item, index) => (
                    <tr key={item.id} className="hover:bg-gray-50">
                      <td className="px-4 py-2">
                        <select
                          value={item.category}
                          onChange={(e) => updateBillItem(item.id, 'category', e.target.value)}
                          className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        >
                          <option value="">Select category</option>
                          {getUniqueCategories().map((category) => (
                            <option key={category} value={category}>
                              {category}
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-4 py-2">
                        <select
                          value={item.subCategory}
                          onChange={(e) => updateBillItem(item.id, 'subCategory', e.target.value)}
                          disabled={!item.category}
                          className="w-full px-2 py-1 text-sm border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        >
                          <option value="">Select sub-category</option>
                          {getSubCategoriesForCategory(item.category).map((subCategory) => (
                            <option key={subCategory} value={subCategory}>
                              {subCategory}
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-4 py-2">
                        <input
                          type="number"
                          value={item.sheetCount}
                          onChange={(e) => updateBillItem(item.id, 'sheetCount', e.target.value)}
                          min="0"
                          className="w-full px-2 py-1 text-sm text-center border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        />
                      </td>
                      <td className="px-4 py-2">
                        <input
                          type="number"
                          value={item.wastCount}
                          onChange={(e) => updateBillItem(item.id, 'wastCount', e.target.value)}
                          min="0"
                          className="w-full px-2 py-1 text-sm text-center border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        />
                      </td>
                      <td className="px-4 py-2">
                        <div className={`w-full px-2 py-1 text-sm text-center border rounded font-medium ${
                          item.wastCount > item.sheetCount 
                            ? 'bg-red-50 border-red-200 text-red-700' 
                            : 'bg-blue-50 border-blue-200 text-blue-700'
                        }`}>
                          {item.totalCount}
                          <div className={`text-xs mt-1 ${
                            item.wastCount > item.sheetCount ? 'text-red-500' : 'text-blue-500'
                          }`}>
                            {item.sheetCount} - {item.wastCount} = {item.totalCount}
                            {item.wastCount > item.sheetCount && (
                              <div className="text-xs font-medium">Wastage exceeds sheets!</div>
                            )}
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-2">
                        <input
                          type="number"
                          value={item.unitPrice}
                          onChange={(e) => updateBillItem(item.id, 'unitPrice', e.target.value)}
                          min="0"
                          step="0.01"
                          className="w-full px-2 py-1 text-sm text-center border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        />
                      </td>
                      <td className="px-4 py-2">
                        <input
                          type="number"
                          value={item.gst}
                          onChange={(e) => updateBillItem(item.id, 'gst', e.target.value)}
                          min="0"
                          max="100"
                          step="0.1"
                          className="w-full px-2 py-1 text-sm text-center border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                        />
                      </td>
                      <td className="px-4 py-2">
                        <div className="w-full px-2 py-1 text-sm text-center bg-gray-50 border border-gray-300 rounded font-medium">
                          {item.amount.toFixed(2)}
                        </div>
                      </td>
                      <td className="px-4 py-2 text-center">
                        <button
                          onClick={() => removeBillItem(item.id)}
                          className="text-red-600 hover:text-red-900"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Totals Section */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Payment Details */}
          <div>
            <h3 className="text-lg font-medium text-gray-900 mb-4">Payment Details</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Payment Method</label>
                <select
                  value={paymentMethod}
                  onChange={(e) => setPaymentMethod(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                >
                  <option value="cash">Cash</option>
                  <option value="upi">UPI</option>
                  <option value="credit_card">Credit Card</option>
                  <option value="bank_transfer">Bank Transfer</option>
                </select>
              </div>
              
              {paymentMethod === 'upi' && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">UPI ID</label>
                  <input
                    type="text"
                    value={upiId}
                    onChange={(e) => setUpiId(e.target.value)}
                    placeholder="Enter UPI ID"
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                  />
                </div>
              )}
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Transaction Number</label>
                <input
                  type="text"
                  value={transactionNo}
                  onChange={(e) => setTransactionNo(e.target.value)}
                  placeholder="Enter transaction number"
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                />
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                <textarea
                  value={notes}
                  onChange={(e) => setNotes(e.target.value)}
                  rows={3}
                  placeholder="Additional notes..."
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm"
                />
              </div>
            </div>
          </div>

          {/* Calculation Summary */}
          <div>
            <h3 className="text-lg font-medium text-gray-900 mb-4">Calculation Summary</h3>
            <div className="bg-gray-50 rounded-lg p-4 space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-600">Subtotal:</span>
                <span className="text-sm font-medium">Rs. {totals.subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-600">Total GST:</span>
                <span className="text-sm font-medium">Rs. {totals.totalGst.toFixed(2)}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-600">Service Charges:</span>
                <input
                  type="number"
                  value={serviceCharges}
                  onChange={(e) => setServiceCharges(e.target.value)}
                  min="0"
                  step="0.01"
                  className="w-20 sm:w-24 px-2 py-1 text-sm text-right border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                />
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-gray-600">Discount:</span>
                <input
                  type="number"
                  value={discount}
                  onChange={(e) => setDiscount(e.target.value)}
                  min="0"
                  step="0.01"
                  className="w-20 sm:w-24 px-2 py-1 text-sm text-right border border-gray-300 rounded focus:ring-1 focus:ring-blue-500"
                />
              </div>
              <div className="border-t pt-3">
                <div className="flex justify-between items-center">
                  <span className="text-base font-bold text-gray-900">Grand Total:</span>
                  <span className="text-base font-bold text-blue-600">Rs. {totals.grandTotal.toFixed(2)}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

export default NewBill
