import { useState, useEffect } from 'react'
import { Bell, Check, CheckCircle, X, Calendar, User, Settings, DollarSign, Package, TrendingUp, AlertCircle, Info, Filter, Trash2, RefreshCw } from 'lucide-react'
import { toast } from 'react-hot-toast'

const NotificationsPage = () => {
  const [notifications, setNotifications] = useState([])
  const [loading, setLoading] = useState(false)
  const [filter, setFilter] = useState('all') // all, unread, read
  const [typeFilter, setTypeFilter] = useState('all') // all, reminder, payment, maintenance, user, system, analytics

  // Initialize empty notifications
  useEffect(() => {
    loadNotifications()
  }, [])

  const loadNotifications = () => {
    setLoading(true)
    
    // Initialize with empty data - will be populated by real API
    setTimeout(() => {
      setNotifications([])
      setLoading(false)
    }, 500)
  }

  const markAsRead = (id) => {
    setNotifications(prev => 
      prev.map(notification => 
        notification.id === id 
          ? { ...notification, unread: false }
          : notification
      )
    )
    toast.success('Notification marked as read')
  }

  const markAllAsRead = () => {
    setNotifications(prev => 
      prev.map(notification => ({ ...notification, unread: false }))
    )
    toast.success('All notifications marked as read')
  }

  const deleteNotification = (id) => {
    setNotifications(prev => prev.filter(n => n.id !== id))
    toast.success('Notification deleted')
  }

  const deleteSelected = (selectedIds) => {
    setNotifications(prev => prev.filter(n => !selectedIds.includes(n.id)))
    toast.success(`${selectedIds.length} notifications deleted`)
  }

  const clearAll = () => {
    if (window.confirm('Are you sure you want to clear all notifications?')) {
      setNotifications([])
      toast.success('All notifications cleared')
    }
  }

  const getFilteredNotifications = () => {
    return notifications.filter(notification => {
      const readFilter = filter === 'all' || (filter === 'unread' && notification.unread) || (filter === 'read' && !notification.unread)
      const typeFilterMatch = typeFilter === 'all' || notification.type === typeFilter
      return readFilter && typeFilterMatch
    })
  }

  const getNotificationIcon = (icon, color) => {
    const IconComponent = icon
    const colorClasses = {
      blue: 'text-blue-500 bg-blue-100',
      green: 'text-green-500 bg-green-100',
      amber: 'text-amber-500 bg-amber-100',
      purple: 'text-purple-500 bg-purple-100',
      gray: 'text-gray-500 bg-gray-100',
      emerald: 'text-emerald-500 bg-emerald-100'
    }
    
    return (
      <div className={`p-3 rounded-full ${colorClasses[color] || 'text-gray-500 bg-gray-100'}`}>
        <IconComponent className="h-6 w-6" />
      </div>
    )
  }

  const getPriorityBadge = (priority) => {
    const badgeClasses = {
      high: 'bg-red-100 text-red-800',
      medium: 'bg-amber-100 text-amber-800',
      low: 'bg-green-100 text-green-800'
    }
    
    return (
      <span className={`inline-flex px-2 py-1 text-xs font-semibold rounded-full ${badgeClasses[priority] || 'bg-gray-100 text-gray-800'}`}>
        {priority.charAt(0).toUpperCase() + priority.slice(1)}
      </span>
    )
  }

  const filteredNotifications = getFilteredNotifications()
  const unreadCount = notifications.filter(n => n.unread).length

  return (
    <div className="p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                <Bell className="h-6 w-6" />
                Notifications
              </h1>
              <p className="text-gray-600 mt-1">
                {unreadCount > 0 ? `${unreadCount} unread notifications` : 'All notifications read'}
              </p>
            </div>
            <div className="flex items-center gap-3">
              <button
                onClick={loadNotifications}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              >
                <RefreshCw className="h-4 w-4" />
                Refresh
              </button>
              {unreadCount > 0 && (
                <button
                  onClick={markAllAsRead}
                  className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
                >
                  <CheckCircle className="h-4 w-4" />
                  Mark All Read
                </button>
              )}
              {notifications.length > 0 && (
                <button
                  onClick={clearAll}
                  className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
                >
                  <Trash2 className="h-4 w-4" />
                  Clear All
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-6">
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2">
              <Filter className="h-4 w-4 text-gray-500" />
              <span className="text-sm font-medium text-gray-700">Filters:</span>
            </div>
            <div className="flex items-center gap-2">
              <label className="text-sm text-gray-600">Status:</label>
              <select
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                className="px-3 py-1 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="all">All</option>
                <option value="unread">Unread</option>
                <option value="read">Read</option>
              </select>
            </div>
            <div className="flex items-center gap-2">
              <label className="text-sm text-gray-600">Type:</label>
              <select
                value={typeFilter}
                onChange={(e) => setTypeFilter(e.target.value)}
                className="px-3 py-1 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              >
                <option value="all">All Types</option>
                <option value="reminder">Reminders</option>
                <option value="payment">Payments</option>
                <option value="maintenance">Maintenance</option>
                <option value="user">Users</option>
                <option value="system">System</option>
                <option value="analytics">Analytics</option>
              </select>
            </div>
          </div>
        </div>

        {/* Notifications List */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200">
          {loading ? (
            <div className="p-8 text-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto"></div>
              <p className="text-gray-500 mt-2">Loading notifications...</p>
            </div>
          ) : filteredNotifications.length === 0 ? (
            <div className="p-8 text-center">
              <Bell className="h-12 w-12 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-500">
                {notifications.length === 0 ? 'No notifications' : 'No notifications match the selected filters'}
              </p>
            </div>
          ) : (
            <div className="divide-y divide-gray-200">
              {filteredNotifications.map((notification) => (
                <div
                  key={notification.id}
                  className={`p-6 hover:bg-gray-50 transition-colors ${
                    notification.unread ? 'bg-blue-50' : ''
                  }`}
                >
                  <div className="flex items-start space-x-4">
                    {getNotificationIcon(notification.icon, notification.color)}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <h3 className="text-lg font-medium text-gray-900">
                            {notification.title}
                          </h3>
                          {getPriorityBadge(notification.priority)}
                          {notification.unread && (
                            <span className="inline-flex px-2 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-800">
                              New
                            </span>
                          )}
                        </div>
                        <div className="flex items-center space-x-2">
                          {notification.unread && (
                            <button
                              onClick={() => markAsRead(notification.id)}
                              className="text-blue-600 hover:text-blue-700 transition-colors"
                              title="Mark as read"
                            >
                              <Check className="h-4 w-4" />
                            </button>
                          )}
                          <button
                            onClick={() => deleteNotification(notification.id)}
                            className="text-gray-400 hover:text-red-600 transition-colors"
                            title="Delete"
                          >
                            <X className="h-4 w-4" />
                          </button>
                        </div>
                      </div>
                      <p className="text-gray-600 mt-2">
                        {notification.message}
                      </p>
                      <div className="flex items-center justify-between mt-4">
                        <p className="text-sm text-gray-400">
                          {notification.time}
                        </p>
                        {notification.actionText && (
                          <button
                            onClick={() => {
                              if (notification.actionUrl) {
                                window.location.href = notification.actionUrl
                              }
                            }}
                            className="text-sm text-blue-600 hover:text-blue-700 transition-colors"
                          >
                            {notification.actionText}
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export default NotificationsPage
