      // Users and settings - using placeholders
      stats.users = { count: 0, size: 0, note: 'Users API not available' }
      stats.settings = { count: 0, size: 0, note: 'Settings API not available' }
      
      // Update collection stats with proper state update
      setMongoDBCollections(prevCollections => {
        const updatedCollections = prevCollections.map(collection => {
          if (stats[collection.name]) {
            return {
              ...collection,
              count: stats[collection.name].count,
              size: stats[collection.name].size,
              error: stats[collection.name].error,
              note: stats[collection.name].note
            }
          }
          return collection
        })
        
        console.log('Updated collections:', updatedCollections)
        return updatedCollections
      })
      
