  // Initialize collection stats and refresh periodically
  React.useEffect(() => {
    fetchCollectionStats()
    
    // Refresh stats every 30 seconds
    const interval = setInterval(() => {
      fetchCollectionStats()
    }, 30000)
    
    return () => clearInterval(interval)
  }, [])

  const handleExport = async () => {
    setIsExporting(true)
    setExportProgress(0)
    
    try {
      // Create backup data structure
      const backupData = {
        metadata: {
          version: '1.0.0',
          timestamp: new Date().toISOString(),
          description: 'Complete site backup',
          totalFiles: pageFiles.length
        },
        files: {}
      }

      // Collect all file contents
      for (let i = 0; i < pageFiles.length; i++) {
        const file = pageFiles[i]
        setExportProgress(Math.round((i / pageFiles.length) * 100))
        
        try {
          // For demonstration, we'll create mock content
          // In a real implementation, you would fetch actual file content from the server
          if (file.type === 'folder') {
            backupData.files[file.name] = {
              type: 'folder',
              path: file.path,
              contents: 'Folder structure - would contain multiple files'
            }
          } else {
            backupData.files[file.name] = {
              type: file.type,
              path: file.path,
              contents: `// Content for ${file.name}\n// This would be the actual file content\n// Exported at ${new Date().toISOString()}`
            }
          }
        } catch (error) {
          console.warn(`Could not backup ${file.name}:`, error)
          backupData.files[file.name] = {
            type: file.type,
            path: file.path,
            error: 'File not accessible'
          }
        }
        
        // Small delay to show progress
        await new Promise(resolve => setTimeout(resolve, 100))
      }
      
      setExportProgress(100)
      
      // Create and download the backup file
      const backupBlob = new Blob([JSON.stringify(backupData, null, 2)], {
        type: 'application/json'
      })
      
      const url = URL.createObjectURL(backupBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `site-backup-${new Date().toISOString().split('T')[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
      
      toast.success('Site backup exported successfully!')
      
    } catch (error) {
      console.error('Export failed:', error)
      toast.error('Failed to export backup. Please try again.')
    } finally {
      setIsExporting(false)
      setExportProgress(0)
    }
  }

  const handleImport = async () => {
    if (!importFile) {
      toast.error('Please select a backup file to import')
      return
    }

    setIsImporting(true)
    setImportProgress(0)
    
    try {
      const fileContent = await importFile.text()
      const backupData = JSON.parse(fileContent)
      
      // Validate backup structure
      if (!backupData.metadata || !backupData.files) {
        throw new Error('Invalid backup file format')
      }
      
      setImportProgress(25)
      
      // Process each file in the backup
      const fileEntries = Object.entries(backupData.files)
      for (let i = 0; i < fileEntries.length; i++) {
        const [fileName, fileData] = fileEntries[i]
        setImportProgress(25 + Math.round((i / fileEntries.length) * 75))
        
        // In a real implementation, you would send this to your backend
        // to restore the files. For now, we'll just simulate the process
        console.log(`Restoring ${fileName}:`, fileData)
        
        // Small delay to show progress
        await new Promise(resolve => setTimeout(resolve, 50))
      }
      
      setImportProgress(100)
      toast.success('Site backup imported successfully!')
      setImportFile(null)
      
      // Reset file input
      const fileInput = document.getElementById('import-file-input')
      if (fileInput) {
        fileInput.value = ''
      }
      
    } catch (error) {
      console.error('Import failed:', error)
      toast.error('Failed to import backup. Please check the file format.')
    } finally {
      setIsImporting(false)
      setImportProgress(0)
    }
  }

  // Comprehensive MongoDB backup function
  const handleFullBackup = async () => {
    setIsFullBackup(true)
    setExportProgress(0)
    
    try {
      const backupData = {
        metadata: {
          version: '2.0.0',
          timestamp: new Date().toISOString(),
          type: 'comprehensive',
          description: 'Complete application data backup including MongoDB collections',
          backupType: backupType,
          totalCollections: selectedCollections.length || mongoDBCollections.length
        },
        collections: {},
        statistics: {
          totalRecords: 0,
          totalSize: 0,
          backupSize: 0
        }
      }
      
      // Determine which collections to backup
      const collectionsToBackup = backupType === 'selected' 
        ? mongoDBCollections.filter(c => selectedCollections.includes(c.name))
        : mongoDBCollections
      
      // Backup each collection
      for (let i = 0; i < collectionsToBackup.length; i++) {
        const collection = collectionsToBackup[i]
        setExportProgress(Math.round((i / collectionsToBackup.length) * 100))
        
        try {
          let collectionData = { records: [], metadata: {} }
          
          switch (collection.name) {
            case 'customers':
              const customersRes = await customersAPI.getAll()
              collectionData.records = customersRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'bills':
              const billsRes = await billsAPI.getAll()
              collectionData.records = billsRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'expenses':
              const expensesRes = await expensesAPI.getAll()
              collectionData.records = expensesRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'machines':
              const machinesRes = await machinesAPI.getAll()
              collectionData.records = machinesRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'maintenance':
              const maintenanceRes = await maintenanceAPI.getAll()
              collectionData.records = maintenanceRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'stock':
              const stockRes = await stockAPI.getAll()
              collectionData.records = stockRes.data || []
              collectionData.metadata = { count: collectionData.records.length, exportedAt: new Date().toISOString() }
              break
              
            case 'staff':
              // staffAPI not available, using empty data
              collectionData.records = []
              collectionData.metadata = { count: 0, exportedAt: new Date().toISOString(), note: 'Staff API not available' }
              break
              
            default:
              // For other collections, create placeholder data
              collectionData.records = []
              collectionData.metadata = { count: 0, exportedAt: new Date().toISOString(), note: 'Collection not accessible via API' }
          }
          
          backupData.collections[collection.name] = collectionData
          backupData.statistics.totalRecords += collectionData.metadata.count
          backupData.statistics.totalSize += JSON.stringify(collectionData.records).length
          
        } catch (error) {
          console.error(`Error backing up ${collection.name}:`, error)
          backupData.collections[collection.name] = {
            records: [],
            metadata: { count: 0, exportedAt: new Date().toISOString(), error: error.message }
          }
        }
        
        // Small delay to show progress
        await new Promise(resolve => setTimeout(resolve, 200))
      }
      
      setExportProgress(100)
      
      // Calculate backup size
      backupData.statistics.backupSize = JSON.stringify(backupData).length
      
      // Create and download the backup file
      const backupBlob = new Blob([JSON.stringify(backupData, null, 2)], {
        type: 'application/json'
      })
      
      const url = URL.createObjectURL(backupBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `full-backup-${new Date().toISOString().split('T')[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
      
      // Add to backup history
      const backupEntry = {
        id: Date.now(),
        timestamp: new Date().toISOString(),
        type: backupType,
        collections: collectionsToBackup.map(c => c.name),
        records: backupData.statistics.totalRecords,
        size: backupData.statistics.backupSize,
        status: 'completed'
      }
      setBackupHistory(prev => [backupEntry, ...prev].slice(0, 10))
      
      toast.success(`Full backup completed! ${backupData.statistics.totalRecords} records backed up.`)
      
    } catch (error) {
      console.error('Full backup failed:', error)
      toast.error('Failed to create full backup. Please try again.')
    } finally {
      setIsFullBackup(false)
      setExportProgress(0)
    }
  }

  // Enhanced database backup function
