import React, { useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import ExpenseCategories from './Settings/ExpenseCategories'
import ExpenseSubCategories from './Settings/ExpenseSubCategories'
import { IndianRupee, Archive } from 'lucide-react'

const ExpenseSettingsWrapper = () => {
  const [searchParams] = useSearchParams()
  const activeSubTab = searchParams.get('subtab') || 'categories'

  const subTabs = [
    { id: 'categories', name: 'Categories', icon: IndianRupee, component: ExpenseCategories },
    { id: 'subcategories', name: 'Subcategories', icon: Archive, component: ExpenseSubCategories }
  ]

  const ActiveComponent = subTabs.find(tab => tab.id === activeSubTab)?.component || ExpenseCategories

  return (
    <div className="h-screen overflow-y-auto">
      {/* Sub-Tab Navigation */}
      <div className="bg-gray-50 rounded-lg border border-gray-200 mb-6 overflow-hidden">
        <nav className="flex overflow-x-auto overflow-y-hidden">
          {subTabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeSubTab === tab.id
            return (
              <a
                key={tab.id}
                href={`/financial?tab=expense-settings&subtab=${tab.id}`}
                onClick={(e) => {
                  e.preventDefault()
                  window.history.pushState({}, '', `/financial?tab=expense-settings&subtab=${tab.id}`)
                  window.dispatchEvent(new PopStateEvent('popstate'))
                }}
                className={`group relative flex items-center flex-shrink-0 px-6 py-3 text-sm font-medium transition-all duration-200 min-w-fit ${
                  isActive
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50 border-r border-gray-200'
                }`}
              >
                <div className="relative z-20 flex items-center justify-center w-full">
                  <Icon className={`mr-2 h-4 w-4 transition-colors duration-200 ${
                    isActive ? 'text-white' : 'text-gray-400 group-hover:text-gray-600'
                  }`} />
                  <span className="relative z-20">{tab.name}</span>
                </div>
                {isActive && (
                  <div className="absolute inset-0 bg-gradient-to-r from-blue-600 to-purple-600"></div>
                )}
                {!isActive && (
                  <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-blue-500 to-purple-500 transform scale-x-0 group-hover:scale-x-100 transition-transform duration-200"></div>
                )}
              </a>
            )
          })}
        </nav>
      </div>

      {/* Sub-Tab Content */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <ActiveComponent />
      </div>
    </div>
  )
}

export default ExpenseSettingsWrapper
